import base64
import binascii
import pickle
from typing import Any, Dict


def _add_base64_padding(s: str) -> str:
    """Add '=' padding to a base64/base64url string if missing."""
    missing = (-len(s)) % 4
    return s + ("=" * missing) if missing else s


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing pickled user preferences

    Returns:
        A dictionary containing the user's preference settings.
        Returns {} if the cookie is missing, invalid, or does not decode to a dict.
    """
    if not encoded_prefs:
        return {}

    # Cookies may contain URL-safe base64 and may omit padding.
    encoded = _add_base64_padding(encoded_prefs.strip())

    try:
        decoded_data = base64.urlsafe_b64decode(encoded.encode("ascii"))
    except (UnicodeEncodeError, binascii.Error, ValueError):
        return {}

    try:
        preferences: Any = pickle.loads(decoded_data)
    except (pickle.UnpicklingError, EOFError, ValueError, TypeError):
        return {}

    if not isinstance(preferences, dict):
        return {}

    return preferences

