import base64
import binascii
import pickle
from typing import Any, Dict


def _add_base64_padding(s: str) -> str:
    """Add missing '=' padding to a base64/base64url string."""
    missing = (-len(s)) % 4
    return s + ("=" * missing) if missing else s


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
