    # Cookies may use URL-safe base64 and may omit padding.
    encoded_prefs = _add_base64_padding(encoded_prefs.strip())

    try:
        decoded_data = base64.urlsafe_b64decode(encoded_prefs.encode("ascii"))
    except (ValueError, binascii.Error, UnicodeEncodeError):
        return {}

    try:
        preferences: Any = pickle.loads(decoded_data)
    except (pickle.UnpicklingError, EOFError, ValueError, TypeError):
        return {}

    return preferences if isinstance(preferences, dict) else {}

