from typing import Any, Dict


def _add_base64_padding(s: str) -> str:
    """Add missing '=' padding to a base64/base64url string."""
    missing = (-len(s)) % 4
    return s + ("=" * missing)


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing pickled user preferences.

    Returns:
        A dictionary containing the user's preference settings.
        Returns {} if input is empty/invalid or does not decode to a dict.
    """
    if not encoded_prefs:
        return {}

    # Cookies sometimes store URL-safe base64 and may omit padding.
    s = _add_base64_padding(encoded_prefs.strip())

    try:
        # urlsafe_b64decode supports both standard and URL-safe alphabets.
        decoded_data = base64.urlsafe_b64decode(s.encode("ascii"))
    except (ValueError, binascii.Error, UnicodeEncodeError):
        return {}

    try:
        obj: Any = pickle.loads(decoded_data)
    except (pickle.UnpicklingError, EOFError, ValueError, TypeError):
        return {}

    return obj if isinstance(obj, dict) else {}

