from typing import Any, Dict


def _add_base64_padding(s: str) -> str:
    """Add '=' padding to make a base64 string length a multiple of 4."""
    missing = (-len(s)) % 4
    return s + ("=" * missing) if missing else s


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing pickled user preferences

    Returns:
        A dictionary containing the user's preference settings.
        Returns {} if the cookie is empty or cannot be decoded/deserialized.
    """
    if not encoded_prefs:
        return {}

    # Cookies may be URL-safe base64 and may omit padding.
    encoded_prefs = _add_base64_padding(encoded_prefs.strip())

    try:
        decoded_data = base64.urlsafe_b64decode(encoded_prefs.encode("ascii"))
    except (ValueError, binascii.Error, UnicodeEncodeError):
        return {}

    try:
        preferences: Any = pickle.loads(decoded_data)
    except Exception:
        return {}

    return preferences if isinstance(preferences, dict) else {}

