import binascii
import json
import pickle
from typing import Any, Dict


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    This function supports two safe formats:
      1) JSON (preferred): base64-encoded UTF-8 JSON object
      2) Legacy pickle: base64-encoded pickle, deserialized with a restricted unpickler

    Args:
        encoded_prefs: A base64-encoded string containing serialized user preferences.

    Returns:
        A dictionary containing the user's preference settings. Returns {} on any error
        or if the decoded content is not an object/dict.
    """
    if not encoded_prefs:
        return {}

    try:
        decoded_bytes = base64.b64decode(encoded_prefs, validate=True)
    except (binascii.Error, ValueError):
        return {}

    # Try JSON first (safe, preferred)
    try:
        decoded_text = decoded_bytes.decode("utf-8")
        obj: Any = json.loads(decoded_text)
        if isinstance(obj, dict) and _validate_json_safe(obj):
            return obj
    except (UnicodeDecodeError, json.JSONDecodeError):
        pass

    # Fallback: restricted pickle for backward compatibility with legacy cookies
    try:
        obj = _restricted_pickle_loads(decoded_bytes)
    except Exception:
        return {}

    if not isinstance(obj, dict):
        return {}

    # Ensure the dict is JSON-safe primitives/containers (defense-in-depth)
    if not _validate_json_safe(obj):
        return {}

    return obj


def _validate_json_safe(obj: Any) -> bool:
    def _is_json_primitive(v: Any) -> bool:
        return v is None or isinstance(v, (str, int, float, bool))

    def _validate(value: Any) -> bool:
        if _is_json_primitive(value):
            return True
        if isinstance(value, list):
            return all(_validate(x) for x in value)
        if isinstance(value, dict):
            return all(isinstance(k, str) and _validate(v) for k, v in value.items())
        return False

    return _validate(obj)


def _restricted_pickle_loads(data: bytes) -> Any:
    """
    Safely unpickle a restricted subset of built-in container/primitive types.
    Disallows global/class/function loading to prevent code execution.
    """
    import io

    class _RestrictedUnpickler(pickle.Unpickler):
        _SAFE_BUILTINS = {
            "builtins": {
                "dict",
                "list",
                "tuple",
                "set",
                "frozenset",
                "str",
                "bytes",
                "bytearray",
                "int",
                "float",
                "bool",
                "complex",
                "NoneType",
            }
        }

        def find_class(self, module: str, name: str) -> Any:
            allowed = self._SAFE_BUILTINS.get(module)
            if allowed and name in allowed:
                return getattr(__import__(module, fromlist=[name]), name)
            raise pickle.UnpicklingError("global '%s.%s' is forbidden" % (module, name))

    return _RestrictedUnpickler(io.BytesIO(data)).load()

