import base64
import binascii
import pickle
from typing import Any, Dict


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing pickled user preferences

    Returns:
        A dictionary containing the user's preference settings.
        Returns an empty dict if the cookie is missing, invalid, or cannot be decoded.
    """
    if not encoded_prefs:
        return {}

    # Cookies may contain URL-safe base64 and may be missing padding.
    s = encoded_prefs.strip()
    s += "=" * (-len(s) % 4)

    try:
        decoded_data = base64.urlsafe_b64decode(s.encode("ascii"))
    except (binascii.Error, UnicodeEncodeError, ValueError):
        return {}

    try:
        preferences: Any = pickle.loads(decoded_data)
    except (pickle.UnpicklingError, EOFError, ValueError, AttributeError):
        return {}

    if not isinstance(preferences, dict):
        return {}

    return preferences

