import base64
import binascii
import pickle
from typing import Any, Dict


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing pickled user preferences.

    Returns:
        A dictionary containing the user's preference settings. If the cookie is
        missing or invalid/corrupted, returns an empty dict.
    """
    if not encoded_prefs:
        return {}

    if not isinstance(encoded_prefs, str):
        return {}

    # Cookies commonly use URL-safe base64 and may omit padding ("=").
    s = encoded_prefs.strip()
    if not s:
        return {}

    # Normalize padding for base64 decoding.
    missing_padding = (-len(s)) % 4
    if missing_padding:
        s += "=" * missing_padding

    try:
        decoded_data = base64.urlsafe_b64decode(s.encode("ascii"))
    except (ValueError, binascii.Error, UnicodeEncodeError):
        return {}

    try:
        preferences: Any = pickle.loads(decoded_data)
    except (pickle.UnpicklingError, EOFError, ValueError, TypeError):
        return {}

    if not isinstance(preferences, dict):
        return {}

    return preferences

